// 날짜 계산: 전일(어제) + 이번 달 + 올해 + 전년 동기
let body = {};
try { body = $('수동 조회').first().json.body || {}; } catch(e) {}
const chatId = String(body.chatId || body.chat_id || '7713811206');

const now = new Date();
const kstOffset = 9 * 60 * 60 * 1000;
const kstNow = new Date(now.getTime() + kstOffset);

const yesterday = new Date(kstNow);
yesterday.setDate(yesterday.getDate() - 1);

const yDate = yesterday.toISOString().slice(0, 10);
const yYear = yDate.slice(0, 4);
const yMonth = yDate.slice(0, 7);
const prevYear = String(parseInt(yYear) - 1);
const prevYearMonth = prevYear + yDate.slice(4, 7);

const p = yDate.split('-').map(Number);
const target = new Date(Date.UTC(p[0], p[1]-1, p[2]));
const jan1 = new Date(Date.UTC(parseInt(yYear), 0, 1));
const sheetsRow = Math.round((target - jan1) / 86400000) + 2;

const dowNames = ['일','월','화','수','목','금','토'];
const dow = dowNames[yesterday.getDay()];
const m = yesterday.getMonth() + 1;
const d = yesterday.getDate();
const mtdDays = d;

return [{ json: {
  chatId, yDate, yYear, yMonth, prevYear, prevYearMonth,
  sheetsRow, dow, monthNum: m, dayNum: d, mtdDays,
  label: `${m}/${d}(${dow}) 확정`,
} }];

// 수동 채널(쿠팡/로켓/기타) 파싱 + 자동 채널 값 확인
const dateInfo = $('날짜 계산').first().json;
const sheetResp = $('Sheets 전일 행 조회').first().json || {};

let row = [];
try {
  const values = sheetResp.values || [[]];
  row = values[0] || [];
} catch(e) {}

const num = (v) => {
  if (v === undefined || v === null || v === '') return 0;
  const s = String(v).replace(/[^0-9.-]/g, '');
  return parseInt(s) || 0;
};

const ms = num(row[0]);
const nv = num(row[1]);
const st = num(row[2]);
const crm = num(row[3]);
const coupang = num(row[4]);
const rocket = num(row[5]);
const etc = num(row[6]);
const sheetTotal = num(row[7]);

const manualEntered = (row.length >= 7) && (row[4] !== '' || row[5] !== '' || row[6] !== '');

return [{ json: {
  sheetRow: row, makeshop: ms, naver: nv, st11: st, crm: crm,
  coupang: coupang, rocket: rocket, etc: etc,
  sheetTotal, manualEntered, dateInfo,
} }];

// NocoDB 수동채널 동기화
// Sheets 수동 채널(쿠팡윙/로켓배송/기타) 입력값을 NocoDB daily_sales에 PATCH
const parsed = $('Sheet 행 파싱').first().json;
const di = parsed.dateInfo;

if (!parsed.manualEntered) {
  return [{ json: { ...parsed, patchResult: 'skipped_no_manual' } }];
}

const cyResp = $('올해 NocoDB 조회').first().json || {};
const cyList = cyResp.list || [];

// 해당 날짜 레코드 찾기 (중복 시 가장 큰 Id)
let target = null;
for (const r of cyList) {
  if (r.report_date === di.yDate) {
    if (!target || r.Id > target.Id) target = r;
  }
}

if (!target) {
  return [{ json: { ...parsed, patchResult: 'no_record_' + di.yDate } }];
}

// total_revenue 재계산: 자동 채널은 NocoDB 기존값, 수동 채널은 Sheets 값
const autoMs = parseInt(target.makeshop_revenue || 0);
const autoNv = parseInt(target.naver_revenue || 0);
const autoSt = parseInt(target.st11_revenue || 0);
const autoCrm = parseInt(target.crm_revenue || 0);
const newTotal = autoMs + autoNv + autoSt + autoCrm + parsed.coupang + parsed.rocket + parsed.etc;

try {
  await this.helpers.httpRequest({
    method: 'PATCH',
    url: 'https://nocodb.pressco21.com/api/v2/tables/mwxvxjiqtw177xu/records',
    headers: {
      'xc-token': $env.NOCODB_TOKEN,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify([{
      Id: target.Id,
      coupang_revenue: parsed.coupang,
      rocket_revenue: parsed.rocket,
      legacy_others_revenue: parsed.etc,
      total_revenue: newTotal,
    }]),
  });
  return [{ json: { ...parsed, patchResult: 'patched_Id=' + target.Id } }];
} catch (e) {
  return [{ json: { ...parsed, patchResult: 'error:' + e.message } }];
}

// 리포트 집계: 올해/작년 NocoDB 데이터 + 전일 채널 데이터
const parsed = $('Sheet 행 파싱').first().json;
const di = parsed.dateInfo;

const cyResp = $('올해 NocoDB 조회').first().json || {};
const pyResp = $('작년 NocoDB 조회').first().json || {};
const cyList = cyResp.list || [];
const pyList = pyResp.list || [];

const dedupe = (list) => {
  const map = {};
  for (const r of list) {
    const d = r.report_date;
    if (!d) continue;
    if (!map[d] || r.Id > map[d].Id) map[d] = r;
  }
  return map;
};
const cyMap = dedupe(cyList);
const pyMap = dedupe(pyList);

let ytdRev = 0, ytdOrd = 0;
for (const d in cyMap) {
  if (d <= di.yDate) {
    ytdRev += parseInt(cyMap[d].total_revenue || 0);
    ytdOrd += parseInt(cyMap[d].total_orders || 0);
  }
}

let mtdRev = 0, mtdOrd = 0;
const mtdDaily = [];
for (const d in cyMap) {
  if (d.startsWith(di.yMonth) && d <= di.yDate) {
    const rev = parseInt(cyMap[d].total_revenue || 0);
    mtdRev += rev;
    mtdOrd += parseInt(cyMap[d].total_orders || 0);
    mtdDaily.push({ date: d, rev });
  }
}
mtdDaily.sort((a, b) => a.date.localeCompare(b.date));

let pytdRev = 0;
const prevSameDay = di.prevYear + di.yDate.slice(4);
for (const d in pyMap) {
  if (d <= prevSameDay) pytdRev += parseInt(pyMap[d].total_revenue || 0);
}

let prevMtdRev = 0;
for (const d in pyMap) {
  if (d.startsWith(di.prevYearMonth) && d <= prevSameDay) prevMtdRev += parseInt(pyMap[d].total_revenue || 0);
}

let prevYearTotal = 0, prevMonthTotal = 0;
for (const d in pyMap) {
  const rev = parseInt(pyMap[d].total_revenue || 0);
  prevYearTotal += rev;
  if (d.startsWith(di.prevYearMonth)) prevMonthTotal += rev;
}

const yesterdayTotal = parsed.makeshop + parsed.naver + parsed.st11 + parsed.crm + parsed.coupang + parsed.rocket + parsed.etc;
const yesterdayOrdersEst = (cyMap[di.yDate] && parseInt(cyMap[di.yDate].total_orders || 0)) || 0;

const fmt = (n) => Math.round(n).toLocaleString('ko-KR');
const pct = (part, whole) => whole > 0 ? Math.round(part / whole * 100) : 0;
const yoy = (cur, prev) => {
  if (!prev || prev === 0) return '-';
  const diff = (cur - prev) / prev * 100;
  return (diff >= 0 ? '+' : '') + diff.toFixed(1) + '%';
};

let msg = `<b>\ud83d\udcb0 \ud1b5\ud569 \uc77c\uc77c \ub9e4\ucd9c \u2014 ${di.label}</b>\n`;
msg += '\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\n';

if (yesterdayTotal === 0 && !parsed.manualEntered) {
  msg += '\u26a0\ufe0f \uc804\uc77c \uc790\ub3d9 \ucc44\ub110 \ub370\uc774\ud130 \uc5c6\uc74c \ub610\ub294 \uc218\uc9d1 \uc2e4\ud328\n';
  msg += '\u26a0\ufe0f \uc218\ub3d9 \ucc44\ub110\ub3c4 \ubbf8\uc785\ub825 (\ucfe0\ud321/\ub85c\ucf13/\uae30\ud0c0)\n\n';
} else {
  msg += `\ud83d\udcca <b>\uc804\uc77c \ucd1d \ub9e4\ucd9c: ${fmt(yesterdayTotal)}\uc6d0</b>`;
  if (yesterdayOrdersEst > 0) msg += ` (${yesterdayOrdersEst}\uac74)`;
  msg += '\n\n<b>\ucc44\ub110\ubcc4:</b>\n';
  msg += `\ud83c\udfea \uba54\uc774\ud06c\uc0f5   ${fmt(parsed.makeshop)}\uc6d0 (${pct(parsed.makeshop, yesterdayTotal)}%)\n`;
  msg += `\ud83d\udfe2 \ub124\uc774\ubc84     ${fmt(parsed.naver)}\uc6d0 (${pct(parsed.naver, yesterdayTotal)}%)\n`;
  msg += `\ud83d\udd34 11\ubc88\uac00     ${fmt(parsed.st11)}\uc6d0 (${pct(parsed.st11, yesterdayTotal)}%)\n`;
  msg += `\ud83d\udcde \uc9c1\uc811\uac70\ub798   ${fmt(parsed.crm)}\uc6d0 (${pct(parsed.crm, yesterdayTotal)}%)\n`;
  if (parsed.manualEntered) {
    msg += `\ud83d\udce6 \ucfe0\ud321\uc719     ${fmt(parsed.coupang)}\uc6d0 (${pct(parsed.coupang, yesterdayTotal)}%)\n`;
    msg += `\ud83d\ude80 \ub85c\ucf13\ubc30\uc1a1   ${fmt(parsed.rocket)}\uc6d0 (${pct(parsed.rocket, yesterdayTotal)}%)\n`;
    if (parsed.etc > 0) msg += `\u26aa \uae30\ud0c0       ${fmt(parsed.etc)}\uc6d0\n`;
  } else {
    msg += '\u23f3 \ucfe0\ud321\uc719/\ub85c\ucf13/\uae30\ud0c0 \u2014 \uc218\ub3d9 \uc785\ub825 \ub300\uae30\n';
  }
  msg += '\n';
}

msg += '\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\n';
msg += `\ud83d\udcc5 <b>\uc774\ubc88 \ub2ec (${di.monthNum}/1~${di.monthNum}/${di.dayNum}, ${di.mtdDays}\uc77c)</b>\n`;
msg += `   \ub204\uacc4: ${fmt(mtdRev)}\uc6d0\n`;
if (di.mtdDays > 0) msg += `   \uc77c\ud3c9\uade0: ${fmt(mtdRev / di.mtdDays)}\uc6d0\n`;
msg += `   \uc804\ub144 \ub3d9\uae30: ${fmt(prevMtdRev)}\uc6d0 (${yoy(mtdRev, prevMtdRev)})\n`;
msg += `   \uc804\ub144 ${di.monthNum}\uc6d4 \uc804\uccb4: ${fmt(prevMonthTotal)}\uc6d0\n\n`;

msg += '\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\n';
msg += `\ud83d\udcc6 <b>\uc62c\ud574 \ub204\uacc4 (1/1 ~ ${di.monthNum}/${di.dayNum})</b>\n`;
msg += `   \ub204\uacc4: ${fmt(ytdRev)}\uc6d0\n`;
msg += `   \uc804\ub144 \ub3d9\uae30: ${fmt(pytdRev)}\uc6d0 (${yoy(ytdRev, pytdRev)})\n`;
msg += `   \uc804\ub144 \uc804\uccb4: ${fmt(prevYearTotal)}\uc6d0\n\n`;

if (mtdDaily.length > 0) {
  msg += '\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\n';
  msg += `\ud83d\udcc8 <b>${di.monthNum}\uc6d4 \uc77c\ubcc4</b>\n`;
  const maxRev = Math.max(...mtdDaily.map(d => d.rev));
  for (const { date, rev } of mtdDaily) {
    const day = parseInt(date.slice(8, 10));
    const barLen = maxRev > 0 ? Math.round(rev / maxRev * 10) : 0;
    const bar = '\u2588'.repeat(barLen) + '\u2581'.repeat(10 - barLen);
    msg += `${String(day).padStart(2, ' ')}\uc77c ${bar} ${fmt(rev)}\n`;
  }
}

// PATCH 결과 표시
try {
  const pr = $('NocoDB \uc218\ub3d9\ucc44\ub110 \ub3d9\uae30\ud654').first().json.patchResult || '';
  if (pr.startsWith('patched')) {
    msg += '\n\u2705 \uc218\ub3d9\ucc44\ub110 \u2192 NocoDB \ub3d9\uae30\ud654 \uc644\ub8cc';
  }
} catch(e) {}

return [{ json: {
  chatId: di.chatId,
  message: msg,
  yDate: di.yDate,
  mtdRev, ytdRev, prevMtdRev, pytdRev,
  manualEntered: parsed.manualEntered,
  parsed,
} }];
